1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const isAliveNextGeneration = (
15	  neighborCount: number,
16	  wasAlive: boolean,
17	): boolean => neighborCount === 3 || (wasAlive && neighborCount === 2);
18	
19	type CandidateCounts = Map<string, { cell: Cell; count: number }>;
20	
21	const countLiveNeighbors = (cells: Cell[]): CandidateCounts => {
22	  const counts: CandidateCounts = new Map();
23	  for (const cell of cells) {
24	    for (const neighbor of neighborsOf(cell)) {
25	      const key = cellKey(neighbor);
26	      const entry = counts.get(key);
27	      if (entry) entry.count += 1;
28	      else counts.set(key, { cell: neighbor, count: 1 });
29	    }
30	  }
31	  return counts;
32	};
33	
34	export const nextGeneration = (cells: Cell[]): Cell[] => {
35	  const liveKeys = new Set(cells.map(cellKey));
36	  const result: Cell[] = [];
37	  for (const { cell, count } of countLiveNeighbors(cells).values()) {
38	    if (isAliveNextGeneration(count, liveKeys.has(cellKey(cell)))) {
39	      result.push(cell);
40	    }
41	  }
42	  return result;
43	};
