1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep block pattern unchanged (still life with 3 neighbors each)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
19	      new Set(["0,0", "1,0", "0,1", "1,1"])
20	    );
21	  });
22	  it("should oscillate blinker pattern (vertical to horizontal)", () => {
23	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
24	    const result = nextGeneration(vertical);
25	    expect(result).toHaveLength(3);
26	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
27	      new Set(["-1,1", "0,1", "1,1"])
28	    );
29	  });
30	  it("should kill overpopulated cell (more than 3 neighbors)", () => {
31	    // Full 3x3 grid: center (1,1) has 8 neighbors, dies from overpopulation
32	    const grid: [number, number][] = [
33	      [0, 0], [1, 0], [2, 0],
34	      [0, 1], [1, 1], [2, 1],
35	      [0, 2], [1, 2], [2, 2],
36	    ];
37	    const result = nextGeneration(grid);
38	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
39	    expect(keys.has("1,1")).toBe(false);
40	  });
41	  it("should birth a dead cell with exactly 3 neighbors (reproduction)", () => {
42	    // L-shape from spec: dead (1,1) has exactly 3 live neighbors -> born
43	    const lShape: [number, number][] = [[0, 0], [1, 0], [0, 1]];
44	    const result = nextGeneration(lShape);
45	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
46	    expect(keys.has("1,1")).toBe(true);
47	  });
48	  it.todo("should handle negative coordinates correctly");
49	});
