export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveKeys = new Set(cells.map(cellKey));
  const result: Cell[] = [];
  for (const [key, { cell, count }] of countLiveNeighbors(cells)) {
    if (isAliveNextGeneration(count, liveKeys.has(key))) {
      result.push(cell);
    }
  }
  return result;
};
